            name: editItem.name,
            basePrice: Number(editItem.basePrice),
            maxPerTeam: Number(editItem.maxPerTeam),
            bidIncrement: Number(editItem.bidIncrement),
            minPerTeam: 0,
            bidLimit: 0,
            slabs: []
